USE LIVE
GO

DROP TABLE #T1

SELECT OB.WORKORDER_TYPE
	, OB.WORKORDER_BASE_ID
	, OB.WORKORDER_LOT_ID
	, OB.WORKORDER_SPLIT_ID
	, OB.WORKORDER_SUB_ID
	, OB.SEQUENCE_NO
	, O.RESOURCE_ID
	, O.OPERATION_TYPE
	, O.[STATUS]
	, CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) AS [BEFORE_OB]
	, OB.BITS AS [OB_BINARY]
	, OB.BITS_LENGTH AS [OB_BITLEN]
INTO #T1
FROM OPERATION O
INNER JOIN OPER_TYPE_BINARY OTB
	ON OTB.OPERATION_TYPE_ID = O.OPERATION_TYPE
INNER JOIN OPERATION_BINARY OB
	ON O.WORKORDER_TYPE = OB.WORKORDER_TYPE
	AND O.WORKORDER_BASE_ID = OB.WORKORDER_BASE_ID
	AND O.WORKORDER_LOT_ID = OB.WORKORDER_LOT_ID
	AND O.WORKORDER_SPLIT_ID = OB.WORKORDER_SPLIT_ID
	AND O.WORKORDER_SUB_ID = OB.WORKORDER_SUB_ID
	AND O.SEQUENCE_NO = OB.SEQUENCE_NO
WHERE (O.WORKORDER_TYPE = 'M')
-- tt 10/26/2020
	AND (CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) LIKE '%INDICATE MASK%'
--		OR CAST(CAST(OB.BITS AS VARBINARY(MAX)) AS NVARCHAR(MAX)) LIKE '%INDICATE MASK%'
		)
	AND RESOURCE_ID IN 
		(SELECT ID
			FROM SHOP_RESOURCE
			WHERE USER_6 IN ('MASKING', 'PENETRANT', 'SHOT PEEN')
			OR USER_7 IN ('MASKING', 'PENETRANT', 'SHOT PEEN')
			OR USER_8 IN ('MASKING', 'PENETRANT', 'SHOT PEEN')
			)

